import pytest
import requests

BASE_URL = "<base_url>"
RATE_LIMIT_THRESHOLD = <rate_limit_n>

@pytest.fixture
def auth_headers():
    return <get_auth_headers_fixture>

@pytest.fixture(autouse=True)
def reset_rate_limit():
    <reset_rate_limit_for_user>
    yield
    <reset_rate_limit_for_user>

def _valid_payload():
    return {
        "week_start": "<current_week_monday>",
        "days": [
            {"day": d, "hours": 0}
            for d in ["monday","tuesday","wednesday","thursday","friday","saturday","sunday"]
        ]
    }

def test_submit_timesheet_rate_limit_exceeded_returns_429(auth_headers):
    for _ in range(RATE_LIMIT_THRESHOLD):
        requests.post(f"{BASE_URL}/timesheets/submit", json=_valid_payload(), headers=auth_headers)
    resp = requests.post(
        f"{BASE_URL}/timesheets/submit",
        json=_valid_payload(),
        headers=auth_headers
    )
    assert resp.status_code == 429
